settings.custom_liquid:
{%- if page.metafields.custom.brochure_pdf -%}
  {%- assign pdf_url = page.metafields.custom.brochure_pdf | file_url -%}
{%- endif -%}

<div id="caqapdf" class="pdf-holder">
  {%- if pdf_url -%}
    Loading brochure...
  {%- else -%}
    No brochure PDF is set. Please assign <strong>custom.brochure_pdf</strong> metafield.
  {%- endif -%}
</div>

<script src="{{ 'pdf.min.js' | asset_url }}"></script>

<script>
  document.addEventListener('DOMContentLoaded', function() {
    const container = document.getElementById('caqapdf');

    if (!container) return;

    const url = "{{ pdf_url }}";
    if (!url) return;

    container.innerHTML = "";

    if (!window['pdfjsLib']) {
      container.textContent = "PDF viewer failed to load (pdf.min.js not loaded).";
      return;
    }

    pdfjsLib.GlobalWorkerOptions.workerSrc = "{{ 'pdf.worker.min.js' | asset_url }}";

    pdfjsLib.getDocument(url).promise.then(function(pdf) {
      const totalPages = pdf.numPages;

      for (let pageNum = 1; pageNum <= totalPages; pageNum++) {
        pdf.getPage(pageNum).then(function(page) {

          const unscaledViewport = page.getViewport({ scale: 1 });
          const maxWidth = 1200;
          const containerWidth = container.clientWidth || window.innerWidth;
          const finalWidth = Math.min(containerWidth, maxWidth);
          const scale = finalWidth / unscaledViewport.width;
          const viewport = page.getViewport({ scale: scale });
          const dpr = window.devicePixelRatio || 1;
          const canvas = document.createElement("canvas");
          const context = canvas.getContext("2d");

          canvas.width = viewport.width * dpr;
          canvas.height = viewport.height * dpr;
          canvas.style.width = viewport.width + "px";
          canvas.style.height = viewport.height + "px";
          canvas.style.display = "block";
          canvas.style.margin = "0 auto 0";
          canvas.style.background = "#FFFFFF";

          container.appendChild(canvas);
          context.setTransform(dpr, 0, 0, dpr, 0, 0);

          page.render({
            canvasContext: context,
            viewport: viewport
          });
        });
      }
    }).catch(function(err) {
      console.error(err);
      container.textContent = "Unable to load PDF.";
    });
  });
</script>

<style>
  .pdf-holder {
    background: #fff;
    overflow-x: hidden;  
    padding: 0;
    max-width: 1200px; 
    margin: 0 auto; 
  }

  .pdf-holder canvas {
    max-width: 100%; 
    height: auto;
    display: block;
  }
</style>
